mapper.select:
SELECT 
    c.id, c.employee_id, c.contract_no, c.contract_type, c.contract_subject,
    c.start_date, c.end_date, c.sign_date, c.contract_status, c.renew_count,
    c.industry_type, c.ext_json, c.remark, c.created_time, c.updated_time,
    e.name as employeeName, e.employee_no as employeeNo
FROM hr_contract c
LEFT JOIN hr_employee e ON c.employee_id = e.id
WHERE c.deleted = 0

    AND c.employee_id = #{query.employeeId}


    AND e.name LIKE CONCAT('%', #{query.employeeName}, '%')


    AND c.contract_no LIKE CONCAT('%', #{query.contractNo}, '%')


    AND c.contract_type = #{query.contractType}


    AND c.contract_status = #{query.contractStatus}


    AND c.start_date >= #{query.startDateBegin}


    AND c.start_date <= #{query.startDateEnd}


    AND c.end_date >= #{query.endDateBegin}


    AND c.end_date <= #{query.endDateEnd}


    AND c.industry_type = #{query.industryType}

ORDER BY c.created_time DESC
